import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useNavigate } from 'react-router-dom';
import UploadContent from './pages/UploadContent';
import LoginPage from './pages/LoginPage';
import PostPage from './pages/PostPage';
import HomePage from './pages/HomePage';
import AboutPage from './pages/AboutPage';
import ContactPage from './pages/ContactPage';
import './App.css';
import 'react-quill/dist/quill.snow.css';
import LoadingSpinner from './components/LoadingSpinner';
import 'leaflet/dist/leaflet.css';

const BASE_URL = 'https://sofia-backend-9l77.onrender.com';

function App() {
  const [posts, setPosts] = useState([]);
  const [isAdmin, setIsAdmin] = useState(false);
  const [email, setEmail] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`${BASE_URL}/posts`)
      .then((res) => res.json())
      .then((data) => setPosts(data))
      .catch((err) => console.error('Error loading posts:', err));
  }, []);

  const handleAddPost = (newPost) => {
    setPosts((prev) => [newPost, ...prev]);
  };

  const handleDeletePost = (index) => {
    fetch(`${BASE_URL}/posts/${index}`, {
      method: 'DELETE',
    })
      .then(() => {
        const updated = [...posts];
        updated.splice(index, 1);
        setPosts(updated);
      })
      .catch((err) => console.error('Failed to delete post:', err));
  };

  const handleLoginSuccess = () => {
    setIsAdmin(true);
    navigate('/blog');
  };

  const handleSubscribe = () => {
    if (!email || !email.includes('@')) {
      alert('Please enter a valid email address');
      return;
    }

    alert(`Subscribed with email: ${email}`);
    setEmail('');
  };

  return (
    <div className="app-container">
      <header className="custom-header">
        <div className="header-left">
          <Link to="/" style={{ textDecoration: 'none' }}>
            <div style={{ display: 'flex', flexDirection: 'column' }}>
              <h1
                className="title"
                style={{
                  fontSize: '2.5rem',
                  marginBottom: '0.3rem',
                  fontWeight: '700',
                  color: '#065f46',
                  fontFamily: "'Playfair Display', serif",
                }}
              >
                Out of Reach
              </h1>
              <span
                style={{
                  fontSize: '0.95rem',
                  fontStyle: 'italic',
                  color: '#2f855a',
                  marginTop: '-0.5rem',
                }}
              >
                a place where Bali meets my thoughts 🌿
              </span>
            </div>
          </Link>
        </div>
        <div className="nav-right">
          <Link to="/" className="nav-button">Home</Link>
          <Link to="/blog" className="nav-button">Blog</Link>
          <Link to="/about" className="nav-button">About</Link>
          <Link to="/contact" className="nav-button">Contact</Link>
        </div>
      </header>

      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route
          path="/blog"
          element={
            <main className="main">
              {posts.length === 0 ? (
                <p>No posts yet.</p>
              ) : (
                posts.map((post, idx) => (
                  <div
                    key={idx}
                    style={{
                      background: 'white',
                      padding: '1rem',
                      margin: '1rem 0',
                      borderRadius: '8px',
                      position: 'relative',
                    }}
                  >
                    <Link to={`/post/${idx}`} style={{ textDecoration: 'none', color: 'black' }}>
                      <h2>{post.title}</h2>
                      {post.date && (
                        <p style={{ fontStyle: 'italic', color: 'gray', marginTop: '-0.5rem' }}>
                          Posted on {post.date}
                        </p>
                      )}
                      {post.previewImage && (
                        <img
                          src={post.previewImage}
                          alt="Preview"
                          style={{
                            width: '100%',
                            maxHeight: '200px',
                            objectFit: 'cover',
                            borderRadius: '8px',
                          }}
                        />
                      )}
                      {post.summary && <p>{post.summary}</p>}
                    </Link>

                    {isAdmin && (
                      <button
                        onClick={() => handleDeletePost(idx)}
                        style={{
                          position: 'absolute',
                          top: '10px',
                          right: '10px',
                          background: 'red',
                          color: 'white',
                          border: 'none',
                          borderRadius: '4px',
                          padding: '4px 8px',
                          cursor: 'pointer',
                        }}
                      >
                        Delete
                      </button>
                    )}
                  </div>
                ))
              )}
            </main>
          }
        />
        <Route path="/login" element={<LoginPage onLoginSuccess={handleLoginSuccess} />} />
        <Route path="/about" element={<AboutPage />} />
        <Route path="/contact" element={<ContactPage />} />
        {isAdmin && <Route path="/upload" element={<UploadContent onAdd={handleAddPost} />} />}
        <Route path="/post/:id" element={<PostPage posts={posts} />} />
      </Routes>

      {/* Floating button or newsletter input */}
      {isAdmin ? (
        <Link to="/upload">
          <button className="floating-add-button">Upload Post</button>
        </Link>
      ) : (
        <div className="newsletter-box">
          <input
            type="email"
            placeholder="Enter your email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="newsletter-input"
          />
          <button className="newsletter-button" onClick={handleSubscribe}>Subscribe</button>
        </div>
      )}
    </div>
  );
}

export default App;
